form:Form.form:Scripts:
		function RegShow()
{
	var ESTADO = Ctrl("LIST").GetSelectAttrValue("ESTADO");
	var ESTADO_EVENTO = Ctrl("LIST").GetSelectAttrValue("ESTADO_EVENTO");
	var ROL = Ctrl("LIST").GetSelectAttrValue("ROL");
	var CAMBIO_ESTADO = Ctrl("LIST").GetSelectAttrValue("CAMBIO_ESTADO");

	// Si el evento esta cerrado se toma como que la evaluacion esta cerrada
	if (ESTADO_EVENTO == 'C') ESTADO = 'CE';

	var modo = '';
	switch(ESTADO){
		case 'AB':
			modo = 'PREEVALUAR';
			break;
		case 'HA': case 'EV': case 'RZ':
			if (ROL == 'O')
				modo = 'EVALUADO';
			if (ROL == 'E')
				modo = 'EVALUADOR';
			if (ROL == 'S')
				modo = 'SUPERVISOR';
			if (ROL == 'F')
				modo = 'EVALUADOR360';
			break;
		case 'CO':
			modo = 'APROBAR';
			break;
		case 'AP':
			modo = 'POSAPROBAR';
			break;
		default:
			modo = 'SHOW';
			break;
	}


	var accion = 'EDIT';
	switch(CAMBIO_ESTADO){
		case 'AR':
			accion = 'APROBAR';
			break;
		case 'CE':
			accion = 'CERRAR';
			break;
		default:
			accion = 'EDIT';
			break;

	}
	if (ESTADO == 'AP') accion = 'CERRAR';
	if (ESTADO == 'CE') accion = 'SHOW';

	appendFormInMain("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION.flow", accion, '<DATA oi_evaluacion="'+Ctrl("LIST").GetXValue()+'" modo="'+modo+'" CAMBIO_ESTADO="'+CAMBIO_ESTADO+'" />');

	return true;
}
